import time
from functools import wraps
from typing import Callable, TypeVar

T = TypeVar("T")


def retry(times: int = 3, delay: float = 0.1) -> Callable[[Callable[..., T]], Callable[..., T]]:
    def decorator(fn: Callable[..., T]) -> Callable[..., T]:
        @wraps(fn)
        def wrapper(*args, **kwargs) -> T:
            last: Exception | None = None
            for attempt in range(1, times + 1):
                try:
                    return fn(*args, **kwargs)
                except Exception as exc:
                    last = exc
                    print(f"retry {attempt}/{times} after {exc}")
                    time.sleep(delay)
            raise last  # type: ignore[misc]
        return wrapper
    return decorator

from dataclasses import dataclass


def tokenize(line: str) -> list[str]:
    return line.strip().split()


@dataclass
class Command:
    name: str
    args: list[str]


def parse(line: str) -> Command:
    parts = tokenize(line)
    if not parts:
        raise ValueError("empty command")
    return Command(parts[0].upper(), parts[1:])

from parser import Command, parse

_store: dict[str, str] = {}


def execute(cmd: Command) -> str:
    if cmd.name == "PING":
        return "PONG"
    if cmd.name == "SET":
        key, value = cmd.args
        _store[key] = value
        return "OK"
    if cmd.name == "GET":
        key = cmd.args[0]
        return _store.get(key, "")
    raise ValueError(f"unknown {cmd.name}")


def handle_line(line: str) -> str:
    return execute(parse(line))

